import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.NoSuchElementException;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

public class GsonTypesTest {

  private static Method indexOfMethod;

  @BeforeAll
  public static void setUp() throws NoSuchMethodException {
    indexOfMethod = $Gson$Types.class.getDeclaredMethod("indexOf", Object[].class, Object.class);
    indexOfMethod.setAccessible(true);
  }

  @Test
  public void testIndexOf_foundAtBeginning() throws InvocationTargetException, IllegalAccessException {
    Object[] array = new Object[] { "a", "b", "c" };
    Object toFind = "a";
    int result = (int) indexOfMethod.invoke(null, array, toFind);
    assertEquals(0, result);
  }

  @Test
  public void testIndexOf_foundAtMiddle() throws InvocationTargetException, IllegalAccessException {
    Object[] array = new Object[] { "a", "b", "c" };
    Object toFind = "b";
    int result = (int) indexOfMethod.invoke(null, array, toFind);
    assertEquals(1, result);
  }

  @Test
  public void testIndexOf_foundAtEnd() throws InvocationTargetException, IllegalAccessException {
    Object[] array = new Object[] { "a", "b", "c" };
    Object toFind = "c";
    int result = (int) indexOfMethod.invoke(null, array, toFind);
    assertEquals(2, result);
  }

  @Test
  public void testIndexOf_notFound_throws() {
    Object[] array = new Object[] { "a", "b", "c" };
    Object toFind = "d";
    assertThrows(NoSuchElementException.class, () -> {
      try {
        indexOfMethod.invoke(null, array, toFind);
      } catch (InvocationTargetException e) {
        throw e.getCause();
      }
    });
  }

  @Test
  public void testIndexOf_nullToFind_throws() {
    Object[] array = new Object[] { "a", "b", "c" };
    Object toFind = null;
    assertThrows(NullPointerException.class, () -> {
      try {
        indexOfMethod.invoke(null, array, toFind);
      } catch (InvocationTargetException e) {
        throw e.getCause();
      }
    });
  }

  @Test
  public void testIndexOf_arrayWithNullElement() throws InvocationTargetException, IllegalAccessException {
    Object[] array = new Object[] { "a", null, "c" };
    Object toFind = null;
    // Since toFind.equals(array[i]) will throw NullPointerException if toFind is null,
    // this test expects NullPointerException.
    assertThrows(NullPointerException.class, () -> {
      try {
        indexOfMethod.invoke(null, array, toFind);
      } catch (InvocationTargetException e) {
        throw e.getCause();
      }
    });
  }
}
